'use client';

import { useEffect, useState } from 'react';
import {
  IconAlertTriangle,
  IconCheck,
  IconLink,
  IconSparkles,
} from '@tabler/icons-react';
import {
  Badge,
  Button,
  Group,
  Loader,
  Modal,
  Stack,
  Text,
  ThemeIcon,
  Title,
} from '@mantine/core';
import classes from './SubscriptionModal.module.css';
import { useSubscription } from '@/src/hooks/use-subscription';

interface SubscriptionModalProps {
  opened: boolean;
  onClose: () => void;
}

export function SubscriptionModal({ opened, onClose }: SubscriptionModalProps) {
  const [errorMsg, setErrorMsg] = useState("");

  const {
    getSubscriptions,
    subscribe
  } = useSubscription()

  const { data: plans, error, isLoading, mutate } = getSubscriptions()


  const { trigger, isMutating } = subscribe({
    successCallback: () => {
      mutate()
    },
    errorCallback: (error: Error) => {
      setErrorMsg(error.message)
    }
  }) 

  useEffect(() => {
    if (opened) mutate();
  }, [opened]);

  return (
    <Modal opened={opened} onClose={onClose} centered title={null} size="md">
      <Stack gap="lg">
        <div>
          <Group gap="xs" justify="center" mb="sm">
            <ThemeIcon color="yellow" size={40} radius="xl">
              <IconAlertTriangle size={22} />
            </ThemeIcon>
          </Group>
          <Title order={3} ta="center">
            You&apos;ve reached your limit
          </Title>
          <Text c="dimmed" ta="center" size="sm" mt={4}>
            Upgrade your plan to create more links and unlock higher quotas.
          </Text>
        </div>

        {isLoading && (
          <Group justify="center" py="lg">
            <Loader color="yellow" />
          </Group>
        )}

        {!isLoading && (errorMsg || error) && (
          <Stack align="center" gap="xs" py="lg">
            <Text c="red" size="sm" ta="center">
              { errorMsg || error.message }
            </Text>
            <Button variant="light" color="yellow" onClick={() => mutate()}>
              Retry
            </Button>
          </Stack>
        )}

        {!isLoading && !error && !errorMsg && (
          <Stack gap="md">
            {(plans || []).map((plan) => (
              <div
                key={plan.subscription_id}
                className={`${classes.planCard} ${plan.subscribed ? classes.planCardCurrent : ''}`}
              >
                <Group justify="space-between" align="flex-start" wrap="nowrap">
                  <div>
                    <Group gap="xs">
                      <Text className={classes.planName} size="lg">
                        {plan.name}
                      </Text>
                      {plan.subscribed && (
                        <Badge color="yellow" variant="light" leftSection={<IconCheck size={12} />}>
                          Current plan
                        </Badge>
                      )}
                    </Group>
                    <Text c="dimmed" size="sm" mt={4}>
                      {plan.description}
                    </Text>
                  </div>
                  <div className={classes.price}>
                    <Title order={2} className={classes.priceValue}>
                      ${plan.price}
                    </Title>
                    <Text c="dimmed" size="xs">
                      /mo
                    </Text>
                  </div>
                </Group>

                <Group gap="xs" mt="sm" mb="md">
                  <ThemeIcon color="yellow" size={20} radius="xl" variant="light">
                    <IconLink size={12} />
                  </ThemeIcon>
                  <Text size="sm">Up to {plan.limit} links per month</Text>
                </Group>

                <Button
                  fullWidth
                  variant={plan.subscribed ? 'default' : 'filled'}
                  color="yellow"
                  disabled={plan.subscribed}
                  loading={isLoading || isMutating}
                  leftSection={!plan.subscribed && <IconSparkles size={16} />}
                  onClick={() => trigger(plan)}
                >
                  {plan.subscribed ? 'Subscribed' : `Upgrade to ${plan.name}`}
                </Button>
              </div>
            ))}
          </Stack>
        )}
      </Stack>
    </Modal>
  );
}
